//=============================================================================
// Platform / Address Map
//=============================================================================
// TODO: Replace these with the real addresses from Vivado xparameters.h

//TODO: check xparameters.h to see if names are correct
#define DMA_DEV_ID           XPAR_AXIDMA_0_DEVICE_ID
#define DMA_BASEADDR         XPAR_XAXIDMA_0_BASEADDR

#define DDR_BASE_ADDR        0x10000000U   /* TODO: replace */
#define ACCEL_BASE_ADDR      0xA0000000U   /* TODO: replace AXI-Lite base */

#define TX_BD_SPACE_BASE     (DDR_BASE_ADDR + 0x00000000U)
#define TX_BD_SPACE_HIGH     (DDR_BASE_ADDR + 0x0001FFFFU)

#define RX_BD_SPACE_BASE     (DDR_BASE_ADDR + 0x00020000U)
#define RX_BD_SPACE_HIGH     (DDR_BASE_ADDR + 0x0003FFFFU)

//TODO: these are just example offsets for A, B, and C in DDR. Adjust as needed based on your memory map and alignment requirements. Make sure they are outside the BD spaces and properly aligned for cache line size if needed.
#define MATRIX_A_BASE        (DDR_BASE_ADDR + 0x00100000U)
#define MATRIX_B_BASE        (DDR_BASE_ADDR + 0x00200000U)
#define MATRIX_C_BASE        (DDR_BASE_ADDR + 0x00300000U)


//=============================================================================
// Accelerator Register Map
//=============================================================================
/* register offsets for control/status. Suggested meaning:

   CTRL    : bit 0 = start
   STATUS  : bit 0 = done, bit 1 = error
   M, K, N : matrix dimensions
   A_BYTES : total packed bytes streamed for A

   This interface is GF(2)-specific, no generic element-size register. */

#define ACCEL_REG_CTRL_OFFSET           0x00U
#define ACCEL_REG_STATUS_OFFSET         0x04U
#define ACCEL_REG_M_OFFSET              0x08U
#define ACCEL_REG_K_OFFSET              0x0CU
#define ACCEL_REG_N_OFFSET              0x10U
#define ACCEL_REG_A_BYTES_OFFSET        0x14U
#define ACCEL_REG_B_BYTES_OFFSET        0x18U
#define ACCEL_REG_C_BYTES_OFFSET        0x1CU

#define ACCEL_CTRL_START_MASK           0x00000001U

#define ACCEL_STATUS_DONE_MASK          0x00000001U
#define ACCEL_STATUS_ERROR_MASK         0x00000002U


//=============================================================================
// Matrix / DMA Job Parameters
//=============================================================================
/* GF(2) only.

   Storage in DDR is packed bit storage:
   - each byte holds 8 GF(2) elements
   - matrix byte counts are derived from bit counts

   For now:
   - matrix sizes are fixed at 256 x 256
   - A is M x K
   - B is K x N
   - C is M x N
   - descriptor payload length is 256 bytes
   - A and B are streamed sequentially on one TX path as two separate frames */

#define MATRIX_M              256U
#define MATRIX_K              256U
#define MATRIX_N              256U
#define BD_TRANSFER_LEN_BYTES 256U
#define POLL_TIMEOUT_COUNTER  1000000U

#define MATRIX_A_BITS     (MATRIX_M * MATRIX_K)
#define MATRIX_B_BITS     (MATRIX_K * MATRIX_N)
#define MATRIX_C_BITS     (MATRIX_M * MATRIX_N)

#define MATRIX_A_BYTES    ((MATRIX_A_BITS + 7U) / 8U)
#define MATRIX_B_BYTES    ((MATRIX_B_BITS + 7U) / 8U)
#define MATRIX_C_BYTES    ((MATRIX_C_BITS + 7U) / 8U)

// integer division but rounded up not down, for calculating descriptor counts
#define CEIL_DIV_U32(value, divisor) \
    (((value) + (divisor) - 1U) / (divisor))

#define TX_BD_COUNT_A        CEIL_DIV_U32(MATRIX_A_BYTES, BD_TRANSFER_LEN_BYTES)
#define TX_BD_COUNT_B        CEIL_DIV_U32(MATRIX_B_BYTES, BD_TRANSFER_LEN_BYTES)
#define TX_BD_COUNT_TOTAL    (TX_BD_COUNT_A + TX_BD_COUNT_B)

#define RX_BD_COUNT_C        CEIL_DIV_U32(MATRIX_C_BYTES, BD_TRANSFER_LEN_BYTES)


//=============================================================================
// UART / Host Packet Definitions
//=============================================================================
/* First host-load version:
   - fixed-size matrices
   - PS UART receive
   - little-endian 32-bit header fields
   - payload order: A bytes, then B bytes */

#define UART_DEV_ID          XPAR_XUARTPS_0_DEVICE_ID   /* TODO: replace if needed */
#define UART_BAUD_RATE       115200U
#define UART_RECV_TIMEOUT_COUNTER 10000000U
//TODO: 10s time out based on baudrate, is this too small?

#define HOST_TO_BOARD_MAGIC  0x4746324DU   /* "GF2M" */
#define HOST_PROTO_VERSION   1U

typedef struct {
    u32 Magic;
    u32 Version;
    u32 ABytes;
    u32 BBytes;
} user_HostToBoardHdr;

//=============================================================================
// Global DMA Instance
//=============================================================================
/* One global DMA driver object is enough for this bare-metal program. */
static XAxiDma AxiDma;
static XUartPs UartPs;

//=============================================================================
// Function Prototypes
//=============================================================================
/* The program is split into initialization, DDR preparation, descriptor submission,
   accelerator launch, completion polling, and cleanup. */

static int  user_DMA_Init(XAxiDma *AxiDmaPtr);
static int  user_Setup_Tx_Ring(XAxiDma *AxiDmaPtr);
static int  user_Setup_Rx_Ring(XAxiDma *AxiDmaPtr);

static int  user_UART_Init(void);
static int  user_UART_Recv_Exact(u8 *Dst, u32 Len);
static int  user_Load_Matrices_From_Host(void);

static void user_write_Matrices_To_DDR(void);
static void user_Flush_ABC_Buffers(void);
static void user_Invalidate_C_cache(void);

static int  user_Submit_Rx_Desc_For_C(XAxiDma *AxiDmaPtr);
static int  user_Submit_Tx_Desc_For_A_B(XAxiDma *AxiDmaPtr);

static void user_Program_Accelerator(void);
static void user_Start_Accelerator(void);
static int  user_Wait_For_Done(void);

static int  user_Drain_Completed_BDs(
    XAxiDma_BdRing *RingPtr,
    u32             ExpectedBdCount,
    const char     *RingName
);

static void user_Report_Completion(void);


//=============================================================================
// main()
//=============================================================================

int main(void) {

    int Status;
    //-----------------
    xil_printf("\r\n--- Accelerator main() start ---\r\n");

    #ifdef __aarch64__
        /* Descriptor memory is shared between CPU and DMA. Marking the BD spaces uncacheable
        avoids stale descriptor contents and stale descriptor status.
        TODO: 
        NORM_NONCACHE | INNER_SHAREABLE come from xil_mmu.h 
        They resolve to 0x701
        
        TODO: these both fall in the same area so one is redundant */
        Xil_SetTlbAttributes(TX_BD_SPACE_BASE, NORM_NONCACHE | INNER_SHAREABLE);
        Xil_SetTlbAttributes(RX_BD_SPACE_BASE, NORM_NONCACHE | INNER_SHAREABLE);
    #endif

    //=================================
    // initialize DMA
    //=================================
    Status = user_DMA_Init(&AxiDma);
    //-----------------
    if (Status != XST_SUCCESS) {
        xil_printf("DMA init failed\r\n");
        //-----------------
        return XST_FAILURE;
    }


    //=================================
    // setup TX ring
    //=================================
    Status = user_Setup_Tx_Ring(&AxiDma);
    //-----------------
    if (Status != XST_SUCCESS) {
        xil_printf("TX ring setup failed\r\n");
        //-----------------
        return XST_FAILURE;
    }


    //=================================
    // setup RX ring
    //================================= 
    Status = user_Setup_Rx_Ring(&AxiDma);
    //-----------------
    if (Status != XST_SUCCESS) {
        xil_printf("RX ring setup failed\r\n");
        //-----------------
        return XST_FAILURE;
    }


    //=================================
    // initialize UART
    //=================================
    Status = user_UART_Init();
    //-----------------
    if (Status != XST_SUCCESS) {
        xil_printf("UART init failed\r\n");
        //-----------------
        return XST_FAILURE;
    }

    //=================================
    // Load matrices to DDR
    //=================================
    // TODO: both uart and fixed matrix load are implemented for now;

    // user_write_Matrices_To_DDR();
    //-----------------
    Status = user_Load_Matrices_From_Host();
    //-----------------
    if (Status != XST_SUCCESS) {
        xil_printf("Matrix receive from host failed\r\n");
        //-----------------
        return XST_FAILURE;
    }

    //=================================
    // Flush A/B/C 
    //=================================
    /* Flush A/B after CPU writes. Also flush C after zeroing. */
    user_Flush_ABC_Buffers();
  

    //=================================
    // Submit RX descriptors for C
    //=================================
    /* RX must be posted before the accelerator starts producing C. */
    Status = user_Submit_Rx_Desc_For_C(&AxiDma);
    //-----------------
    if (Status != XST_SUCCESS) {
        xil_printf("RX descriptor submission failed\r\n");
        //-----------------
        return XST_FAILURE;
    }
    

    //=================================
    // Submit TX descriptors for A and B
    //=================================
    /* TX is one sequential stream carrying two GF(2) frames: first A, then B. */
    Status = user_Submit_Tx_Desc_For_A_B(&AxiDma);
    //-----------------
    if (Status != XST_SUCCESS) {
        xil_printf("TX descriptor submission failed\r\n");
        //-----------------
        return XST_FAILURE;
    }
    

    //=================================
    // Program accelerator
    //=================================
    user_Program_Accelerator();
    

    //=================================
    // Start accelerator
    //=================================
    user_Start_Accelerator();
    

    //=================================
    // poll for accelerator done
    //=================================
    // TODO: The accelerator is assumed to clear old status internally before next start. 
    Status = user_Wait_For_Done();
    //-----------------
    if (Status != XST_SUCCESS) {
        xil_printf("Accelerator reported failure or timeout\r\n");
        //-----------------
        return XST_FAILURE;
    }


    //=================================
    // Drain completed descriptors and verify
    //=================================
    /* accelerator Might report done but software should still reclaim and free all
       completed BDs and verify completion/error flags. */
    Status = user_Drain_Completed_BDs(
        XAxiDma_GetTxRing(&AxiDma),
        TX_BD_COUNT_TOTAL,
        "TX"
    );
    //-----------------
    if (Status != XST_SUCCESS) {
        xil_printf("TX completion drain failed\r\n");
        //-----------------
        return XST_FAILURE;
    }


    //=================================
    // Drain completed descriptors and verify for RX
    //=================================
    Status = user_Drain_Completed_BDs(
        XAxiDma_GetRxRing(&AxiDma),
        RX_BD_COUNT_C,
        "RX"
    );
    //-----------------
    if (Status != XST_SUCCESS) {
        xil_printf("RX completion drain failed\r\n");
        //-----------------
        return XST_FAILURE;
    }

    //=================================
    // Invalidate C cache lines before reading results
    //=================================
    user_Invalidate_C_cache();
    

    //=================================
    // Report completion 
    //=================================
    user_Report_Completion();
    

    xil_printf("--- Accelerator main() done ---\r\n");
    return XST_SUCCESS;

}



//=============================================================================
// DMA Initialization
//=============================================================================

static int user_DMA_Init(XAxiDma *AxiDmaPtr) {
    
    XAxiDma_Config *Config;
    int             Status;

    //=================================
    // lookup DMA config
    //=================================
    /* TODO: Modern AMD unified flow uses base address rather than DEVICE_ID. */
    // Config = XAxiDma_LookupConfig(DMA_DEV_ID);
    Config = XAxiDma_LookupConfig(DMA_BASEADDR);
    //-----------------
    if (Config == NULL) {
        xil_printf("No DMA config found for base 0x%08x\r\n", 
            (unsigned int)DMA_BASEADDR);
        //-----------------
        return XST_FAILURE;
    }


    //=================================
    // initialize DMA driver object
    //=================================
    Status = XAxiDma_CfgInitialize(AxiDmaPtr, Config);
    //-----------------
    if (Status != XST_SUCCESS) {
        xil_printf(
            "XAxiDma_CfgInitialize failed: %d\r\n",
            Status
        );
        //-----------------
        return XST_FAILURE;
    }


    //=================================
    // verify SG mode
    //=================================
    if (!XAxiDma_HasSg(AxiDmaPtr)) {
        xil_printf("DMA is not configured in SG mode\r\n");
        //-----------------
        return XST_FAILURE;
    }

    return XST_SUCCESS;
}


//=============================================================================
// TX Ring Setup
//=============================================================================

static int user_Setup_Tx_Ring(XAxiDma *AxiDmaPtr)
{
    XAxiDma_BdRing *TxRingPtr;
    XAxiDma_Bd      BdTemplate;
    u32             BdCount;
    int             Status;

    //=================================
    // get TX ring handle
    //=================================
    TxRingPtr = XAxiDma_GetTxRing(AxiDmaPtr);


    //=================================
    // disable TX interrupts
    //=================================
    XAxiDma_BdRingIntDisable(TxRingPtr, XAXIDMA_IRQ_ALL_MASK);


    //=================================
    // set coalescing policy
    //=================================
    Status = XAxiDma_BdRingSetCoalesce(TxRingPtr, 1, 0);
    //-----------------
    if (Status != XST_SUCCESS) {
        xil_printf("TX coalesce setup failed: %d\r\n", Status);
        return XST_FAILURE;
    }

    //=================================
    // calculate TX ring capacity
    //=================================
    BdCount = XAxiDma_BdRingCntCalc(
        XAXIDMA_BD_MINIMUM_ALIGNMENT,
        TX_BD_SPACE_HIGH - TX_BD_SPACE_BASE + 1U
    );
    //-----------------
    if (BdCount < TX_BD_COUNT_TOTAL) {
        xil_printf(
            "TX BD space too small: have %d need %d\r\n",
            (int)BdCount,
            (int)TX_BD_COUNT_TOTAL
        );
        //-----------------
        return XST_FAILURE;
    }

    //=================================
    // create TX ring
    //=================================
    Status = XAxiDma_BdRingCreate(
        TxRingPtr,
        TX_BD_SPACE_BASE,
        TX_BD_SPACE_BASE,
        XAXIDMA_BD_MINIMUM_ALIGNMENT,
        BdCount
    );
    //-----------------
    if (Status != XST_SUCCESS) {
        xil_printf("TX ring create failed: %d\r\n", Status);
        //-----------------
        return XST_FAILURE;
    }

    //=================================
    // clear template BD
    //=================================
    XAxiDma_BdClear(&BdTemplate);

    //=================================
    // clone template into TX ring
    //=================================
    Status = XAxiDma_BdRingClone(TxRingPtr, &BdTemplate);
    //-----------------
    if (Status != XST_SUCCESS) {
        xil_printf("TX ring clone failed: %d\r\n", Status);
        //-----------------
        return XST_FAILURE;
    }

    return XST_SUCCESS;
}


