//=============================================================================
// UART Exact Receive
//=============================================================================
/* Blocking receive helper.
   Keeps reading until the requested number of bytes has arrived. */

static int user_UART_Recv_Exact(u8 *Dst, u32 Len){
 
    u32 ReceivedNow;
    u32 TotalReceived;
    u32 IdleTimeOut;

    //=================================
    // initialize receive state
    //=================================
    TotalReceived = 0U;
    IdleTimeOut   = 0U;

    //=================================
    // receive until full payload arrives or timeout expires
    //=================================
    while (TotalReceived < Len) {
        ReceivedNow = XUartPs_Recv(
            &UartPs,
            &Dst[TotalReceived],
            Len - TotalReceived
        );
        //-----------------
        if (ReceivedNow > 0U) {
            TotalReceived += ReceivedNow;
            IdleTimeOut    = 0U;
            continue;
        }
        //-----------------
        if (IdleTimeOut++ >= UART_RECV_TIMEOUT_COUNTER) {
            xil_printf("UART receive timeout: got %u of %u bytes\r\n",
                    (unsigned int)TotalReceived,
                    (unsigned int)Len);
            //-----------------
            return XST_FAILURE;
        }
        //-----------------
        usleep(1U);
    }

    return XST_SUCCESS;
}

//=============================================================================
// Matrix Load From Host
//=============================================================================
/* Receive fixed-size packed A and B from the host through PS UART.

   Expected packet:
   - 16-byte header:
       Magic
       Version
       ABytes
       BBytes
   - A payload
   - B payload

   C is still cleared locally on the target. */

static int user_Load_Matrices_From_Host(void)
{
    user_HostToBoardHdr Hdr;

    u8 *A = (u8 *)MATRIX_A_BASE;
    u8 *B = (u8 *)MATRIX_B_BASE;
    u8 *C = (u8 *)MATRIX_C_BASE;

    int Status;

    //=================================
    // wait for host packet
    //=================================
    xil_printf("Waiting for host matrix packet...\r\n");


    //=================================
    // receive host header
    //=================================
    Status = user_UART_Recv_Exact((u8 *)&Hdr, sizeof(Hdr));
    //-----------------
    if (Status != XST_SUCCESS) {
        xil_printf("Host header receive failed\r\n");
        //-----------------
        return XST_FAILURE;
    }


    //=================================
    // validate host magic
    //=================================
    if (Hdr.Magic != HOST_TO_BOARD_MAGIC) {
        xil_printf("Bad host magic: 0x%08x\r\n", (unsigned int)Hdr.Magic);
        //-----------------
        return XST_FAILURE;
    }


    //=================================
    // validate protocol version
    //=================================
    if (Hdr.Version != HOST_PROTO_VERSION) {
    xil_printf("Bad host version: %u\r\n", (unsigned int)Hdr.Version);
        //-----------------
        return XST_FAILURE;
    }

    //=================================
    // validate A byte count
    //=================================
    if (Hdr.ABytes != MATRIX_A_BYTES) {
        xil_printf("Bad A byte count: got %u expected %u\r\n",
                (unsigned int)Hdr.ABytes,
                (unsigned int)MATRIX_A_BYTES);
        //-----------------
        return XST_FAILURE;
    }

    //=================================
    // validate B byte count
    //=================================
    if (Hdr.BBytes != MATRIX_B_BYTES) {
        xil_printf("Bad B byte count: got %u expected %u\r\n",
                (unsigned int)Hdr.BBytes,
                (unsigned int)MATRIX_B_BYTES);
        //-----------------
        return XST_FAILURE;
    }

    //=================================
    // receive packed matrix A
    //=================================
    xil_printf("Receiving packed matrix A...\r\n");
    //-----------------
    Status = user_UART_Recv_Exact(A, MATRIX_A_BYTES);
    //-----------------
    if (Status != XST_SUCCESS) {
        xil_printf("A receive failed\r\n");
        //-----------------
        return XST_FAILURE;
    }

    //=================================
    // receive packed matrix B
    //=================================
    xil_printf("Receiving packed matrix B...\r\n");
    //-----------------
    Status = user_UART_Recv_Exact(B, MATRIX_B_BYTES);
    //-----------------
    if (Status != XST_SUCCESS) {
        xil_printf("B receive failed\r\n");
        //-----------------
        return XST_FAILURE;
    }


    //=================================
    // clear packed matrix C
    //=================================
    memset(C, 0, MATRIX_C_BYTES);


    //=================================
    // report receive completion
    //=================================
    xil_printf("Host matrix receive complete\r\n");

    return XST_SUCCESS;
}


//=============================================================================
// Matrix Load
//=============================================================================

static void user_write_Matrices_To_DDR(void)
{
    u8 *A = (u8 *)MATRIX_A_BASE;
    u8 *B = (u8 *)MATRIX_B_BASE;
    u8 *C = (u8 *)MATRIX_C_BASE;

    u32 i;

    //=================================
    // fill packed matrix A
    //=================================
    for (i = 0U; i < MATRIX_A_BYTES; i++) {
        A[i] = (u8)(i & 0xFFU);
    }


    //=================================
    // fill packed matrix B
    //=================================
    for (i = 0U; i < MATRIX_B_BYTES; i++) {
        B[i] = (u8)((i + 0x55U) & 0xFFU);
    }


    //=================================
    // clear packed matrix C
    //=================================
    memset(C, 0, MATRIX_C_BYTES);
}


//=============================================================================
// Cache Maintenance Before Start
//=============================================================================

static void user_Flush_ABC_Buffers(void)
{
    //=================================
    // flush packed matrix A
    //=================================
    Xil_DCacheFlushRange((UINTPTR)MATRIX_A_BASE, MATRIX_A_BYTES);


    //=================================
    // flush packed matrix B
    //=================================
    Xil_DCacheFlushRange((UINTPTR)MATRIX_B_BASE, MATRIX_B_BYTES);


    //=================================
    // flush packed matrix C
    //=================================
    Xil_DCacheFlushRange((UINTPTR)MATRIX_C_BASE, MATRIX_C_BYTES);
}


//=============================================================================
// RX Descriptor Submission for Matrix C
//=============================================================================

/* Allocate the exact number of RX descriptors
   needed for packed matrix C, attach DDR
   destination addresses, assign lengths, and
   submit them to hardware.

   C is produced by the accelerator and written
   to DDR through the DMA S2MM channel, so these
   descriptors must be posted before start.

   C is treated as one output frame on the RX
   side. RX control is left zero and frame status
   is reported back by hardware. */

   static int user_Submit_Rx_Desc_For_C(XAxiDma *AxiDmaPtr)
{
    XAxiDma_BdRing *RxRingPtr;
    XAxiDma_Bd     *BdPtr;
    XAxiDma_Bd     *BdCurPtr;
    UINTPTR         CurAddr;
    u32             RemainingBytes;
    u32             ChunkLen;
    u32             i;
    int             Status;

    //=================================
    // get RX ring handle
    //=================================
    RxRingPtr = XAxiDma_GetRxRing(AxiDmaPtr);


    //=================================
    // allocate RX descriptors
    //=================================
    Status = XAxiDma_BdRingAlloc(
        RxRingPtr,
        RX_BD_COUNT_C,
        &BdPtr
    );
    //-----------------
    if (Status != XST_SUCCESS) {
        xil_printf("RX alloc failed: %d\r\n", Status);
        //-----------------
        return XST_FAILURE;
    }


    //=================================
    // initialize RX descriptor walk state
    //=================================
    BdCurPtr       = BdPtr;
    CurAddr        = (UINTPTR)MATRIX_C_BASE;
    RemainingBytes = MATRIX_C_BYTES;


    //=================================
    // program RX descriptors for C buffer
    //=================================
    for (i = 0U; i < RX_BD_COUNT_C; i++) {
        ChunkLen = (RemainingBytes > BD_TRANSFER_LEN_BYTES) ?
                   BD_TRANSFER_LEN_BYTES : RemainingBytes;


        //=================================
        // set RX buffer address
        //=================================
        Status = XAxiDma_BdSetBufAddr(BdCurPtr, CurAddr);
        //-----------------
        if (Status != XST_SUCCESS) {
            xil_printf(
                "RX set buf addr failed on BD %d\r\n",
                (int)i
            );
            //-----------------
            goto rx_unalloc_allocated_bds;
        }


        //=================================
        // set RX transfer length
        //=================================
        Status = XAxiDma_BdSetLength(
            BdCurPtr,
            ChunkLen,
            RxRingPtr->MaxTransferLen
        );
        //-----------------
        if (Status != XST_SUCCESS) {
            xil_printf(
                "RX set length failed on BD %d\r\n",
                (int)i
            );
            //-----------------
            goto rx_unalloc_allocated_bds;
        }


        //=================================
        // set RX control and software ID
        //=================================
        XAxiDma_BdSetCtrl(BdCurPtr, 0U);
        XAxiDma_BdSetId(BdCurPtr, CurAddr);


        //=================================
        // advance to next RX descriptor
        //=================================
        CurAddr        += ChunkLen;
        RemainingBytes -= ChunkLen;
        //-----------------
        BdCurPtr = (XAxiDma_Bd *)XAxiDma_BdRingNext(
            RxRingPtr,
            BdCurPtr
        );
    }


    //=================================
    // submit RX descriptors to hardware
    //=================================
    Status = XAxiDma_BdRingToHw(
        RxRingPtr,
        RX_BD_COUNT_C,
        BdPtr
    );
    //-----------------
    if (Status != XST_SUCCESS) {
        xil_printf("RX ToHw failed: %d\r\n", Status);
        //-----------------
        Status = XAxiDma_BdRingUnAlloc(RxRingPtr, RX_BD_COUNT_C, BdPtr);
        //-----------------
        if (Status != XST_SUCCESS) {
            xil_printf("RX ToHw cleanup unalloc failed: %d\r\n", Status);
        }
        //-----------------
        return XST_FAILURE;
    }


    //=================================
    // start RX ring
    //=================================
    Status = XAxiDma_BdRingStart(RxRingPtr);
    //-----------------
    if (Status != XST_SUCCESS) {
        xil_printf("RX ring start failed: %d\r\n", Status);
        //-----------------
        return XST_FAILURE;
    }

    return XST_SUCCESS;

    //=================================
    // error cleanup: unallocate any RX descriptors
    //=================================
    rx_unalloc_allocated_bds:

        Status = XAxiDma_BdRingUnAlloc(
            RxRingPtr,
            RX_BD_COUNT_C,
            BdPtr
        );
        //-----------------
        if (Status != XST_SUCCESS) {
            xil_printf("RX cleanup unalloc failed: %d\r\n", Status);
        }
        //-----------------
        return XST_FAILURE;

}

//=============================================================================
// TX Descriptor Submission for Matrix A then Matrix B
//=============================================================================
/* Allocate the exact number of TX descriptors
   needed for A and B, then bind them in one
   sequential TX stream.

   Stream order:
   [ A frame ][ B frame ]

   A and B are sent as two separate AXI-Stream
   frames:
   - first TX BD of A -> SOF
   - last  TX BD of A -> EOF
   - first TX BD of B -> SOF
   - last  TX BD of B -> EOF

   If your bridge later changes scheduling, only
   this function should need major edits. */

static int user_Submit_Tx_Desc_For_A_B(XAxiDma *AxiDmaPtr) {

    XAxiDma_BdRing *TxRingPtr;
    XAxiDma_Bd     *BdPtr;
    XAxiDma_Bd     *BdCurPtr;
    UINTPTR         CurAddr;
    u32             RemainingBytes;
    u32             ChunkLen;
    u32             Ctrl;
    u32             aBdIndex;
    u32             bBdIndex;
    int             Status;

    //=================================
    // get TX ring handle
    //=================================
    TxRingPtr = XAxiDma_GetTxRing(AxiDmaPtr);


    //=================================
    // allocate TX descriptors
    //=================================
    Status = XAxiDma_BdRingAlloc(
        TxRingPtr,
        TX_BD_COUNT_TOTAL,
        &BdPtr
    );
    //-----------------
    if (Status != XST_SUCCESS) {
        xil_printf("TX alloc failed: %d\r\n", Status);
        //-----------------
        return XST_FAILURE;
    }


    //=================================
    // initialize TX descriptor walk state
    //=================================
    BdCurPtr = BdPtr;


    //=================================
    // program descriptors for matrix A
    //=================================
    /* A is its own AXI-Stream frame:
       - first BD gets SOF
       - last  BD gets EOF */
    CurAddr        = (UINTPTR)MATRIX_A_BASE;
    RemainingBytes = MATRIX_A_BYTES;
    aBdIndex       = 0U;

    while (RemainingBytes != 0U) {
        ChunkLen = (RemainingBytes > BD_TRANSFER_LEN_BYTES) ?
                   BD_TRANSFER_LEN_BYTES : RemainingBytes;

        Ctrl = 0U;
        //-----------------
        if (aBdIndex == 0U) {
            Ctrl |= XAXIDMA_BD_CTRL_TXSOF_MASK;
        }
        //-----------------
        if (aBdIndex == (TX_BD_COUNT_A - 1U)) {
            Ctrl |= XAXIDMA_BD_CTRL_TXEOF_MASK;
        }


        //=================================
        // set A buffer address
        //=================================
        Status = XAxiDma_BdSetBufAddr(BdCurPtr, CurAddr);
        //-----------------
        if (Status != XST_SUCCESS) {
            xil_printf(
                "TX set A buf addr failed on BD %d\r\n",
                (int)aBdIndex
            );
            //-----------------
            goto tx_unalloc_allocated_bds;
        }


        //=================================
        // set A transfer length
        //=================================
        Status = XAxiDma_BdSetLength(
            BdCurPtr,
            ChunkLen,
            TxRingPtr->MaxTransferLen
        );
        //-----------------
        if (Status != XST_SUCCESS) {
            xil_printf(
                "TX set A length failed on BD %d\r\n",
                (int)aBdIndex
            );
            //-----------------
            goto tx_unalloc_allocated_bds;
        }


        //=================================
        // set A control and software ID
        //=================================
        XAxiDma_BdSetCtrl(BdCurPtr, Ctrl);
        XAxiDma_BdSetId(BdCurPtr, CurAddr);


        //=================================
        // advance to next A descriptor
        //=================================
        CurAddr        += ChunkLen;
        RemainingBytes -= ChunkLen;
        aBdIndex++;
        //-----------------
        BdCurPtr = (XAxiDma_Bd *)XAxiDma_BdRingNext(
            TxRingPtr,
            BdCurPtr
        );
    }


    //=================================
    // program descriptors for matrix B
    //=================================
    /* B is its own AXI-Stream frame:
       - first BD gets SOF
       - last  BD gets EOF */
    CurAddr        = (UINTPTR)MATRIX_B_BASE;
    RemainingBytes = MATRIX_B_BYTES;
    bBdIndex       = 0U;

    while (RemainingBytes != 0U) {
        ChunkLen = (RemainingBytes > BD_TRANSFER_LEN_BYTES) ?
                   BD_TRANSFER_LEN_BYTES : RemainingBytes;

        Ctrl = 0U;
        //-----------------
        if (bBdIndex == 0U) {
            Ctrl |= XAXIDMA_BD_CTRL_TXSOF_MASK;
        }
        //-----------------
        if (bBdIndex == (TX_BD_COUNT_B - 1U)) {
            Ctrl |= XAXIDMA_BD_CTRL_TXEOF_MASK;
        }


        //=================================
        // set B buffer address
        //=================================
        Status = XAxiDma_BdSetBufAddr(BdCurPtr, CurAddr);
        //-----------------
        if (Status != XST_SUCCESS) {
            xil_printf(
                "TX set B buf addr failed on BD %d\r\n",
                (int)bBdIndex
            );
            //-----------------
            goto tx_unalloc_allocated_bds;
        }


        //=================================
        // set B transfer length
        //=================================
        Status = XAxiDma_BdSetLength(
            BdCurPtr,
            ChunkLen,
            TxRingPtr->MaxTransferLen
        );
        //-----------------
        if (Status != XST_SUCCESS) {
            xil_printf(
                "TX set B length failed on BD %d\r\n",
                (int)bBdIndex
            );
            //-----------------
            goto tx_unalloc_allocated_bds;
        }


        //=================================
        // set B control and software ID
        //=================================
        XAxiDma_BdSetCtrl(BdCurPtr, Ctrl);
        XAxiDma_BdSetId(BdCurPtr, CurAddr);


        //=================================
        // advance to next B descriptor
        //=================================
        CurAddr        += ChunkLen;
        RemainingBytes -= ChunkLen;
        bBdIndex++;
        //-----------------
        BdCurPtr = (XAxiDma_Bd *)XAxiDma_BdRingNext(
            TxRingPtr,
            BdCurPtr
        );
    }


    //=================================
    // submit TX descriptors to hardware
    //=================================
    Status = XAxiDma_BdRingToHw(
        TxRingPtr,
        TX_BD_COUNT_TOTAL,
        BdPtr
    );
    //-----------------
    if (Status != XST_SUCCESS) {
        xil_printf("TX ToHw failed: %d\r\n", Status);
        //-----------------
        Status = XAxiDma_BdRingUnAlloc(TxRingPtr, TX_BD_COUNT_TOTAL, BdPtr);
        //-----------------
        if (Status != XST_SUCCESS) {
            xil_printf("TX ToHw cleanup unalloc failed: %d\r\n", Status);
        }
        //-----------------
        return XST_FAILURE;
    }


    //=================================
    // start TX ring
    //=================================
    Status = XAxiDma_BdRingStart(TxRingPtr);
    //-----------------
    if (Status != XST_SUCCESS) {
        xil_printf("TX ring start failed: %d\r\n", Status);
        //-----------------
        return XST_FAILURE;
    }
    //-----------------
    return XST_SUCCESS;

    //=================================
    // error cleanup: unallocate any TX BDs that were allocated
    //=================================
    tx_unalloc_allocated_bds:
        Status = XAxiDma_BdRingUnAlloc(
            TxRingPtr,
            TX_BD_COUNT_TOTAL,
            BdPtr
        );
        //-----------------
        if (Status != XST_SUCCESS) {
            xil_printf("TX cleanup unalloc failed: %d\r\n", Status);
        }
        //-----------------
        return XST_FAILURE;
}


//=============================================================================
// Accelerator Programming
//=============================================================================

static void user_Program_Accelerator(void)
{
    //=================================
    // program matrix dimension M
    //=================================
    Xil_Out32(ACCEL_BASE_ADDR + ACCEL_REG_M_OFFSET, MATRIX_M);


    //=================================
    // program matrix dimension K
    //=================================
    Xil_Out32(ACCEL_BASE_ADDR + ACCEL_REG_K_OFFSET, MATRIX_K);


    //=================================
    // program matrix dimension N
    //=================================
    Xil_Out32(ACCEL_BASE_ADDR + ACCEL_REG_N_OFFSET, MATRIX_N);


    //=================================
    // program packed A byte count
    //=================================
    Xil_Out32(ACCEL_BASE_ADDR + ACCEL_REG_A_BYTES_OFFSET, MATRIX_A_BYTES);


    //=================================
    // program packed B byte count
    //=================================
    Xil_Out32(ACCEL_BASE_ADDR + ACCEL_REG_B_BYTES_OFFSET, MATRIX_B_BYTES);


    //=================================
    // program packed C byte count
    //=================================
    Xil_Out32(ACCEL_BASE_ADDR + ACCEL_REG_C_BYTES_OFFSET, MATRIX_C_BYTES);
}


//=============================================================================
// Accelerator Start
//=============================================================================

/* Assert the start bit once DMA and metadata
   setup is complete.

   This assumes the accelerator accepts a write
   of START=1 as a valid launch event and handles
   its own internal start/status sequencing. */

static void user_Start_Accelerator(void)
{
    //=================================
    // assert accelerator start bit
    //=================================
    Xil_Out32(
        ACCEL_BASE_ADDR + ACCEL_REG_CTRL_OFFSET,
        ACCEL_CTRL_START_MASK
    );
}


//=============================================================================
// Accelerator Done Poll
//=============================================================================
/* Poll the accelerator status register until done, error, or timeout. */

static int user_Wait_For_Done(void)
{
    u32 StatusReg;
    u32 TimeOut;

    //=================================
    // poll accelerator status
    //=================================
    for (TimeOut = 0U; TimeOut < POLL_TIMEOUT_COUNTER; TimeOut++) {
        StatusReg = Xil_In32(
            ACCEL_BASE_ADDR + ACCEL_REG_STATUS_OFFSET
        );


        //=================================
        // check accelerator error bit
        //=================================
        if ((StatusReg & ACCEL_STATUS_ERROR_MASK) != 0U) {
            xil_printf(
                "Accelerator error status: 0x%08x\r\n",
                (unsigned int)StatusReg
            );
            //-----------------
            return XST_FAILURE;
        }


        //=================================
        // check accelerator done bit
        //=================================
        if ((StatusReg & ACCEL_STATUS_DONE_MASK) != 0U) {
            return XST_SUCCESS;
        }

        //-----------------
        usleep(1U);
    }

    xil_printf("Accelerator done timeout\r\n");
    return XST_FAILURE;
}


//=============================================================================
// DMA Completion Drain
//=============================================================================
/* Pull processed descriptors back from hardware
   until the expected count has been reclaimed.

   For every processed BD:
   - verify the BD reports completion
   - verify the BD does not report an error
   - then free the BDs back to the software
     free pool

   This is the required SG cleanup step after
   the hardware side is done. */

   //TODO: are we draining only once at the end to avoid DDR contention?

static int user_Drain_Completed_BDs(
    XAxiDma_BdRing *RingPtr,
    u32             ExpectedBdCount,
    const char     *RingName
){
    XAxiDma_Bd *BdPtr;
    XAxiDma_Bd *BdCurPtr;
    u32         BdSts;
    u32         TotalProcessed;
    int         ProcessedNow;
    int         Status;
    u32         TimeOut;
    int         Index;

    //=================================
    // initialize completion tracking
    //=================================
    TotalProcessed = 0U;
    TimeOut        = 0U;


    //=================================
    // drain completed BDs until expected count is reached
    //=================================
    while (TotalProcessed < ExpectedBdCount) {
        ProcessedNow = XAxiDma_BdRingFromHw(
            RingPtr,
            XAXIDMA_ALL_BDS,
            &BdPtr
        );


        //=================================
        // process returned BDs
        //=================================
        if (ProcessedNow > 0) {
            BdCurPtr = BdPtr;

            //-----------------
            for (Index = 0; Index < ProcessedNow; Index++) {
                BdSts = XAxiDma_BdGetSts(BdCurPtr);


                //=================================
                // check BD error status
                //=================================
                if ((BdSts & XAXIDMA_BD_STS_ALL_ERR_MASK) != 0U) {
                    xil_printf(
                        "%s BD error status: 0x%08x\r\n",
                        RingName,
                        (unsigned int)BdSts
                    );
                    //-----------------
                    XAxiDma_BdRingFree(RingPtr, ProcessedNow, BdPtr);
                    //-----------------
                    return XST_FAILURE;
                }


                //=================================
                // check BD completion status
                //=================================
                if ((BdSts & XAXIDMA_BD_STS_COMPLETE_MASK) == 0U) {
                    xil_printf(
                        "%s BD incomplete status: 0x%08x\r\n",
                        RingName,
                        (unsigned int)BdSts
                    );
                    //-----------------
                    XAxiDma_BdRingFree(RingPtr, ProcessedNow, BdPtr);
                    //-----------------
                    return XST_FAILURE;
                }


                //=================================
                // move to next returned BD
                //=================================
                BdCurPtr = (XAxiDma_Bd *)XAxiDma_BdRingNext(
                    RingPtr,
                    BdCurPtr
                );
            }


            //=================================
            // free processed BDs back to ring
            //=================================
            Status = XAxiDma_BdRingFree(
                RingPtr,
                ProcessedNow,
                BdPtr
            );
            //-----------------
            if (Status != XST_SUCCESS) {
                xil_printf(
                    "%s ring free failed: %d\r\n",
                    RingName,
                    Status
                );
                //-----------------
                return XST_FAILURE;
            }


            //=================================
            // update drain progress
            //=================================
            TotalProcessed += (u32)ProcessedNow;
            TimeOut         = 0U;
            //-----------------
            continue;
        }


        //=================================
        // check drain timeout
        //=================================
        if (TimeOut++ >= POLL_TIMEOUT_COUNTER) {
            xil_printf(
                "%s ring completion timeout\r\n",
                RingName
            );
            //-----------------
            return XST_FAILURE;
        }

        //-----------------
        usleep(1U);
    }

    return XST_SUCCESS;
}


//=============================================================================
// Cache Invalidate for Matrix C
//=============================================================================
/* Invalidate packed matrix C after DMA has written it so the
   CPU reads fresh DDR contents rather than stale cache lines. */

static void user_Invalidate_C_cache(void)
{
    //=================================
    // invalidate packed matrix C
    //=================================
    Xil_DCacheInvalidateRange((UINTPTR)MATRIX_C_BASE, MATRIX_C_BYTES);
}


//=============================================================================
// Completion Report
//=============================================================================
/* This is a placeholder completion report.
   Right now it only prints the base address of
   packed C and the first few bytes.

   Later this can become:
   - UART upload of packed matrix C
   - host response packet
   - correctness check
   - performance counter printout */

static void user_Report_Completion(void)
{
    u8 *C = (u8 *)MATRIX_C_BASE;

    //=================================
    // print job status
    //=================================
    xil_printf("Job complete\r\n");


    //=================================
    // print packed C base address
    //=================================
    xil_printf(
        "Packed matrix C DDR base: 0x%08x\r\n",
        (unsigned int)MATRIX_C_BASE
    );


    //=================================
    // print packed matrix sizes
    //=================================
    xil_printf(
        "Packed matrix sizes: A=%d B=%d C=%d bytes\r\n",
        (int)MATRIX_A_BYTES,
        (int)MATRIX_B_BYTES,
        (int)MATRIX_C_BYTES
    );


    //=================================
    // print first 16 bytes of packed C
    //=================================
    xil_printf("C[0..15] = ");
    //-----------------
    xil_printf(
        "%02x %02x %02x %02x %02x %02x %02x %02x ",
        C[0],
        C[1],
        C[2],
        C[3],
        C[4],
        C[5],
        C[6],
        C[7]
    );
    //-----------------
    xil_printf(
        "%02x %02x %02x %02x %02x %02x %02x %02x\r\n",
        C[8],
        C[9],
        C[10],
        C[11],
        C[12],
        C[13],
        C[14],
        C[15]
    );
}